import "core-js/modules/es.array.push.js";
import quoteSettingsService from '../services/quoteSettingsService';
export default {
  name: 'ConfigGeneral',
  data() {
    return {
      settings: {
        quote_number_prefix: 'DEVIS',
        quote_number_separator: '-',
        quote_number_year_format: 'YYYY',
        quote_number_padding: 3,
        quote_number_counter: 0,
        quote_number_reset_yearly: true,
        email_notifications_enabled: false,
        email_on_quote_created: false,
        email_on_quote_validated: false,
        email_on_quote_refused: false,
        email_on_quote_expiring: false,
        email_expiring_days_before: 3,
        email_sender_name: 'Service Devis',
        email_sender_email: '',
        email_reply_to: ''
      },
      loading: true,
      saving: false,
      error: null,
      successMessage: null
    };
  },
  computed: {
    previewQuoteNumber() {
      const {
        quote_number_prefix,
        quote_number_separator,
        quote_number_year_format,
        quote_number_padding
      } = this.settings;
      let parts = [];
      if (quote_number_prefix) {
        parts.push(quote_number_prefix);
      }
      if (quote_number_year_format) {
        const year = new Date().getFullYear();
        const yearStr = quote_number_year_format === 'YY' ? String(year).slice(-2) : String(year);
        parts.push(yearStr);
      }
      const counter = String(1).padStart(quote_number_padding || 3, '0');
      parts.push(counter);
      return parts.join(quote_number_separator || '-');
    }
  },
  async mounted() {
    await this.loadSettings();
  },
  methods: {
    async loadSettings() {
      console.log("Loading settings...");
      try {
        this.loading = true;
        this.error = null;
        const data = await quoteSettingsService.get();
        console.log('Settings loaded:', data);
        if (data) {
          // Normalisation des clés pour correspondre à l'objet settings
          const normalizedData = {
            quote_number_prefix: data.quoteNumberPrefix,
            quote_number_separator: data.quoteNumberSeparator,
            quote_number_year_format: data.quoteNumberYearFormat,
            quote_number_padding: data.quoteNumberPadding
          };
          this.settings = {
            ...this.settings,
            ...normalizedData
          };
        }
      } catch (err) {
        this.error = 'Erreur lors du chargement: ' + err.message;
        console.error(err);
      } finally {
        this.loading = false;
      }
    },
    async saveSettings() {
      try {
        this.saving = true;
        this.error = null;
        this.successMessage = null;
        await quoteSettingsService.update(this.settings);
        this.successMessage = 'Configuration enregistrée avec succès';
        setTimeout(() => {
          this.successMessage = null;
        }, 3000);
      } catch (err) {
        this.error = 'Erreur lors de l\'enregistrement: ' + err.message;
        console.error(err);
      } finally {
        this.saving = false;
      }
    }
  }
};
